#!/usr/bin/env node

/**
 * Smart Model Selector
 * Analisa economia-tokens.md e task-models.yml
 * Recomenda o melhor modelo para cada tarefa com base em:
 * - Score da tarefa
 * - Custo (economia de tokens)
 * - Tipo de task (HAIKU/SONNET/OPUS)
 */

const fs = require('fs');
const path = require('path');
const yaml = require('js-yaml');

class SmartModelSelector {
  constructor(templatesDir = __dirname) {
    this.templatesDir = templatesDir;
    this.economiaTokens = null;
    this.taskModels = null;
    this.analysis = {};
  }

  /**
   * Carrega os arquivos necessários
   */
  loadFiles() {
    const economiaPath = path.join(this.templatesDir, 'economia-tokens (1).md');
    const taskModelsPath = path.join(this.templatesDir, 'task-models.yml');

    if (!fs.existsSync(economiaPath)) {
      throw new Error(`Arquivo não encontrado: ${economiaPath}`);
    }
    if (!fs.existsSync(taskModelsPath)) {
      throw new Error(`Arquivo não encontrado: ${taskModelsPath}`);
    }

    this.economiaTokens = fs.readFileSync(economiaPath, 'utf-8');
    this.taskModels = yaml.load(fs.readFileSync(taskModelsPath, 'utf-8'));

    console.log('✅ Arquivos carregados com sucesso\n');
  }

  /**
   * Extrai a categoria de modelo recomendado da economia-tokens
   */
  getModelCategory(taskDescription) {
    const desc = taskDescription.toLowerCase();

    // HAIKU - Simples, rápido, execução
    const haikuKeywords = [
      'cleanup', 'format', 'organiz', 'extract', 'buscar',
      'pegar', 'listar', 'status', 'simples', 'read',
      'classify', 'sort', 'tag'
    ];

    // SONNET - Criação, análise, código
    const sonnetKeywords = [
      'criat', 'escrit', 'gerar', 'análise', 'analisar',
      'código', 'refactor', 'resumir', 'email', 'copy',
      'content', 'summary', 'extraction'
    ];

    // OPUS - Estratégia, decisão, arquitetura
    const opusKeywords = [
      'estratég', 'decidir', 'arquitet', 'planej', 'planning',
      'reasoning', 'complex', 'profund'
    ];

    if (haikuKeywords.some(k => desc.includes(k))) return 'HAIKU';
    if (sonnetKeywords.some(k => desc.includes(k))) return 'SONNET';
    if (opusKeywords.some(k => desc.includes(k))) return 'OPUS';

    // Default baseado no tamanho
    if (desc.length < 50) return 'HAIKU';
    if (desc.length < 200) return 'SONNET';
    return 'OPUS';
  }

  /**
   * Calcula score final baseado em:
   * - Score empírico/estimado
   * - Custo
   * - Latência
   * - Categoria de modelo recomendado
   */
  calculateScore(model, modelCategory) {
    const score = model.score || model.score_estimated || 0;
    const inputCost = model.cost_per_1m_input || 0;
    const outputCost = model.cost_per_1m_output || 0;
    const totalCost = inputCost + outputCost;
    const latency = model.avg_latency_s || 0;

    // Penalidade por custo: -0.1 pontos por cada $1 de custo
    const costPenalty = Math.min(totalCost * 0.1, 2);

    // Penalidade por latência: -0.05 por cada 10s
    const latencyPenalty = Math.min(latency * 0.005, 1);

    // Bônus se o modelo é free
    const freeBônus = model.free_available ? 1.0 : 0;

    // Score final
    const finalScore = (score - costPenalty - latencyPenalty + freeBônus).toFixed(2);

    return {
      finalScore: parseFloat(finalScore),
      baseScore: score,
      costPenalty,
      latencyPenalty,
      freeBônus
    };
  }

  /**
   * Analisa todas as tarefas e recomenda modelos
   */
  analyzeAllTasks() {
    const tasks = this.taskModels.tasks || {};
    const recommendations = {};

    for (const [taskName, taskConfig] of Object.entries(tasks)) {
      const category = this.getModelCategory(taskConfig.description);
      const models = taskConfig.models || [];

      // Calcula score para cada modelo
      const scoredModels = models.map(m => ({
        ...m,
        scoreDetails: this.calculateScore(m, category)
      }));

      // Ordena por score final
      scoredModels.sort((a, b) =>
        b.scoreDetails.finalScore - a.scoreDetails.finalScore
      );

      recommendations[taskName] = {
        description: taskConfig.description,
        recommendedCategory: category,
        validationStatus: taskConfig.validation_status,
        topModel: scoredModels[0],
        alternatives: scoredModels.slice(1, 3),
        allModels: scoredModels
      };
    }

    this.analysis = recommendations;
    return recommendations;
  }

  /**
   * Gera relatório formatado
   */
  generateReport() {
    console.log('═'.repeat(80));
    console.log('🎯 SMART MODEL SELECTOR - RECOMENDAÇÕES INTELIGENTES');
    console.log('═'.repeat(80));
    console.log('');

    const tasks = Object.entries(this.analysis);

    for (const [taskName, analysis] of tasks) {
      const top = analysis.topModel;
      const scoreDetails = top.scoreDetails;

      console.log(`📋 ${taskName.toUpperCase()}`);
      console.log(`   ${analysis.description}`);
      console.log(`   Categoria: ${analysis.recommendedCategory} | Status: ${analysis.validationStatus}`);
      console.log('');
      console.log(`   ✅ MELHOR MODELO: ${top.id}`);
      console.log(`      Score final: ${scoreDetails.finalScore} (base: ${scoreDetails.baseScore})`);
      console.log(`      Custo: $${(top.cost_per_1m_input + top.cost_per_1m_output).toFixed(2)}/1M tokens`);
      if (top.avg_latency_s) {
        console.log(`      Latência média: ${top.avg_latency_s}s`);
      }
      if (top.free_available) {
        console.log(`      🎉 FREE disponível!`);
      }
      console.log(`      Notas: ${top.notes}`);
      console.log('');

      if (analysis.alternatives.length > 0) {
        console.log(`   📌 ALTERNATIVAS:`);
        analysis.alternatives.forEach((alt, idx) => {
          console.log(`      ${idx + 1}. ${alt.id}`);
          console.log(`         Score: ${alt.scoreDetails.finalScore}`);
          console.log(`         Custo: $${(alt.cost_per_1m_input + alt.cost_per_1m_output).toFixed(2)}/1M`);
        });
        console.log('');
      }

      console.log('-'.repeat(80));
      console.log('');
    }

    return this.analysis;
  }

  /**
   * Responde à pergunta específica do usuário
   */
  answerQuestion(question) {
    console.log('\n💬 PERGUNTA: ' + question);
    console.log('');

    const recommendations = this.analyzeAllTasks();

    // Resumo por categoria
    const byCategory = { HAIKU: [], SONNET: [], OPUS: [] };
    for (const [taskName, analysis] of Object.entries(recommendations)) {
      byCategory[analysis.recommendedCategory].push({
        task: taskName,
        model: analysis.topModel.id,
        score: analysis.topModel.scoreDetails.finalScore
      });
    }

    console.log('📊 RESUMO RECOMENDAÇÕES POR CATEGORIA:\n');

    console.log('🚀 HAIKU (Rápido & Barato - Execução):');
    if (byCategory.HAIKU.length > 0) {
      byCategory.HAIKU.forEach(item => {
        console.log(`   • ${item.task}: ${item.model} (score: ${item.score})`);
      });
    } else {
      console.log('   (nenhuma tarefa)');
    }
    console.log('');

    console.log('✨ SONNET (Criação & Análise):');
    if (byCategory.SONNET.length > 0) {
      byCategory.SONNET.forEach(item => {
        console.log(`   • ${item.task}: ${item.model} (score: ${item.score})`);
      });
    } else {
      console.log('   (nenhuma tarefa)');
    }
    console.log('');

    console.log('👑 OPUS (Estratégia & Decisão):');
    if (byCategory.OPUS.length > 0) {
      byCategory.OPUS.forEach(item => {
        console.log(`   • ${item.task}: ${item.model} (score: ${item.score})`);
      });
    } else {
      console.log('   (nenhuma tarefa)');
    }
    console.log('');

    // Melhor modelo FREE
    console.log('💰 MELHOR CUSTO-BENEFÍCIO (modelos FREE):');
    let foundFree = false;
    for (const [taskName, analysis] of Object.entries(recommendations)) {
      const freeModel = analysis.allModels.find(m => m.free_available);
      if (freeModel) {
        console.log(`   • ${taskName}: ${freeModel.id} (score: ${freeModel.scoreDetails.finalScore})`);
        foundFree = true;
      }
    }
    if (!foundFree) {
      console.log('   (nenhum modelo free encontrado)');
    }

    console.log('\n' + '='.repeat(80));
  }

  /**
   * Executa análise completa
   */
  run(question = null) {
    try {
      this.loadFiles();
      this.analyzeAllTasks();

      if (question) {
        this.answerQuestion(question);
      } else {
        this.generateReport();
      }
    } catch (error) {
      console.error('❌ Erro:', error.message);
      process.exit(1);
    }
  }
}

// CLI
if (require.main === module) {
  const selector = new SmartModelSelector(process.cwd());
  const question = process.argv[2] || null;
  selector.run(question);
}

module.exports = SmartModelSelector;

