#!/usr/bin/env node

/**
 * Select Model Analyzer
 * Analisa modelos com comparação a modelo atual
 *
 * Uso:
 * node select-model-analyzer.js --current=modelo_id --task=task_name
 * node select-model-analyzer.js --free-only
 */

const fs = require('fs');
const path = require('path');
const yaml = require('js-yaml');

class SelectModelAnalyzer {
  constructor(templatesDir = __dirname) {
    this.templatesDir = templatesDir;
    this.taskModels = null;
    this.currentModel = null;
    this.targetTask = null;
    this.freeOnly = false;
    this.provider = null;
  }

  /**
   * Parseia argumentos CLI
   */
  parseArgs(args) {
    args.forEach(arg => {
      if (arg.startsWith('--current=')) {
        this.currentModel = arg.replace('--current=', '');
      } else if (arg.startsWith('--task=')) {
        this.targetTask = arg.replace('--task=', '');
      } else if (arg.startsWith('--provider=')) {
        this.provider = arg.replace('--provider=', '');
      } else if (arg === '--free-only') {
        this.freeOnly = true;
      }
    });
  }

  /**
   * Carrega task-models.yml
   */
  loadTaskModels() {
    const taskModelsPath = path.join(this.templatesDir, 'task-models.yml');
    if (!fs.existsSync(taskModelsPath)) {
      throw new Error(`Arquivo não encontrado: ${taskModelsPath}`);
    }
    this.taskModels = yaml.load(fs.readFileSync(taskModelsPath, 'utf-8'));
  }

  /**
   * Calcula economia percentual
   */
  calculateEconomy(currentCost, recommendedCost) {
    if (currentCost === 0) return 0;
    return ((currentCost - recommendedCost) / currentCost) * 100;
  }

  /**
   * Formata economia para exibição
   */
  formatEconomy(economy) {
    if (economy > 50) return `🔴 ${economy.toFixed(1)}% (URGENTE!)`;
    if (economy > 20) return `🟡 ${economy.toFixed(1)}% (Recomendado)`;
    if (economy > 0) return `🟢 ${economy.toFixed(1)}% (Opcional)`;
    if (economy < -20) return `⚠️ ${Math.abs(economy).toFixed(1)}% mais caro (mas melhor qualidade)`;
    return `➡️ ${Math.abs(economy).toFixed(1)}% (similar)`;
  }

  /**
   * Analisa tarefa específica
   */
  analyzeTask(taskName) {
    const taskConfig = this.taskModels.tasks[taskName];
    if (!taskConfig) {
      console.log(`❌ Tarefa não encontrada: ${taskName}`);
      return null;
    }

    let models = taskConfig.models || [];

    // Filtra por provider se especificado
    if (this.provider) {
      models = models.filter(m => m.provider === this.provider);
    }

    // Filtra apenas modelos FREE se flag --free-only
    if (this.freeOnly) {
      models = models.filter(m => m.free_available);
    }

    // Calcula score para cada modelo
    const scoredModels = models.map(m => {
      const inputCost = m.cost_per_1m_input || 0;
      const outputCost = m.cost_per_1m_output || 0;
      const totalCost = inputCost + outputCost;

      return {
        ...m,
        totalCost,
        score: m.score || m.score_estimated || 0
      };
    });

    // Ordena por score
    scoredModels.sort((a, b) => b.score - a.score);

    return {
      description: taskConfig.description,
      status: taskConfig.validation_status,
      models: scoredModels
    };
  }

  /**
   * Analisa comparação com modelo atual
   */
  analyzeComparison(taskName) {
    if (!this.currentModel) {
      console.log('⚠️  Use --current=model_id para comparar com seu modelo atual\n');
      return null;
    }

    const analysis = this.analyzeTask(taskName);
    if (!analysis) return null;

    // Encontra modelo atual
    const currentModelData = analysis.models.find(m => m.id === this.currentModel);
    if (!currentModelData) {
      console.log(`❌ Modelo atual não encontrado em task-models.yml: ${this.currentModel}\n`);
      console.log('Modelos disponíveis:');
      analysis.models.forEach(m => console.log(`   • ${m.id}`));
      return null;
    }

    // Recomendado é o primeiro (melhor score)
    const recommended = analysis.models[0];

    // Calcula economia
    const economy = this.calculateEconomy(
      currentModelData.totalCost,
      recommended.totalCost
    );

    return {
      ...analysis,
      currentModel: currentModelData,
      recommendedModel: recommended,
      economy,
      alternatives: analysis.models.slice(1, 3)
    };
  }

  /**
   * Exibe resultado de comparação
   */
  displayComparison(taskName) {
    console.log('\n' + '═'.repeat(80));
    console.log(`🔄 COMPARAÇÃO DE MODELO - ${taskName.toUpperCase()}`);
    console.log('═'.repeat(80) + '\n');

    const comparison = this.analyzeComparison(taskName);
    if (!comparison) return;

    // Exibe descrição da tarefa
    console.log(`📋 ${comparison.description}`);
    console.log(`Status: ${comparison.status}\n`);

    // Modelo atual
    console.log('📌 MODELO ATUAL:');
    console.log(`   ${comparison.currentModel.id}`);
    console.log(`   Custo: $${comparison.currentModel.totalCost.toFixed(2)}/1M tokens`);
    console.log(`   Score: ${comparison.currentModel.score}`);
    console.log('');

    // Recomendado
    console.log('✅ MODELO RECOMENDADO:');
    console.log(`   ${comparison.recommendedModel.id}`);
    console.log(`   Custo: $${comparison.recommendedModel.totalCost.toFixed(2)}/1M tokens`);
    console.log(`   Score: ${comparison.recommendedModel.score}`);
    console.log('');

    // Economia
    const economyText = this.formatEconomy(comparison.economy);
    console.log('💰 ECONOMIA:');
    console.log(`   ${economyText}`);

    // Score comparison
    const scoreDiff = comparison.recommendedModel.score - comparison.currentModel.score;
    if (scoreDiff > 0) {
      console.log(`   Score melhor: +${scoreDiff.toFixed(2)} pontos`);
    } else if (scoreDiff < 0) {
      console.log(`   Score pior: ${scoreDiff.toFixed(2)} pontos`);
    } else {
      console.log('   Score equivalente');
    }

    console.log('');

    // Alternativas
    if (comparison.alternatives.length > 0) {
      console.log('📌 ALTERNATIVAS:');
      comparison.alternatives.forEach((alt, idx) => {
        const altEconomy = this.calculateEconomy(
          comparison.currentModel.totalCost,
          alt.totalCost
        );
        const altEconomyText = this.formatEconomy(altEconomy);
        console.log(`   ${idx + 1}. ${alt.id}`);
        console.log(`      Custo: $${alt.totalCost.toFixed(2)}/1M | Score: ${alt.score}`);
        console.log(`      Economia: ${altEconomyText}`);
      });
      console.log('');
    }

    // Recomendação
    if (comparison.economy >= 50) {
      console.log('🔴 RECOMENDAÇÃO URGENTE:');
      console.log('   Trocar AGORA! Grande economia de tokens sem perder qualidade.');
    } else if (comparison.economy >= 20) {
      console.log('🟡 RECOMENDAÇÃO FORTE:');
      console.log('   Considere trocar no próximo ciclo para economizar tokens.');
    } else if (comparison.economy >= 0) {
      console.log('🟢 RECOMENDAÇÃO OPCIONAL:');
      console.log('   Econômico, mas benefício marginal.');
    } else {
      console.log('⚠️  AVISO:');
      console.log('   Modelo recomendado é mais caro, mas com qualidade superior.');
    }

    console.log('\n' + '═'.repeat(80) + '\n');
